VALUES
  ('optician-moex-02409', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '根據Hofstetter最小調節幅度公式判斷，下列何者最可能有調節不足（accommodative insufficiency）的情形？', '["20歲患者，調節幅度8.00 D", "30歲患者，調節幅度7.00 D", "40歲患者，調節幅度6.00 D", "50歲患者，調節幅度2.50 D"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "f7d946344465", "answer_pdf_sha1": "922ed7560375", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02410', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '在測量近用加入度（ADD）時，以虛性相對調節力（NRA；negative relative accommodation）及實性相對 調節力（PRA：positive relative accommodation）對加入度進行微調。若NRA為+1.50 D，PRA為-1.00 D， 而暫定加入度為+1.25 D。則最終加入度為何？', '["+1.00 D", "+1.25 D", "+1.50 D", "+1.75 D"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "f7d946344465", "answer_pdf_sha1": "922ed7560375", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02411', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受檢者50歲正視眼，調節幅度為2.50 D。其手機閱讀距離為33 cm，書籍閱讀距離為40 cm。根據二分之 一調節預留原則（half the amplitude in reserve）計算，此兩距離需要的加入度各為多少？', '["+1.25 D；+0.75 D", "+1.75 D；+1.25 D", "+2.25 D；+1.75 D", "+2.50 D；+2.00 D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "f7d946344465", "answer_pdf_sha1": "922ed7560375", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02412', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列那些測驗可用來決定老花近用加入度數？①負鏡片模糊法（minus lens to blur）  ②虛性相對調節／', '["融像性交叉圓柱鏡測試（fused cross cylinder, FCC）", "僅", "", "僅"]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "f7d946344465", "answer_pdf_sha1": "922ed7560375", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02413', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受檢者為正視眼，使用原有的單焦老花眼鏡看桌上型電腦螢幕經常不清楚，經過檢查後其調節力為1.50 D， 且戴上該副眼鏡的最近能閱讀的距離為25 cm。在不考慮景深（depth of focus）的狀態下，配戴此副眼鏡 時電腦螢幕距離最遠幾cm還可以看清楚？', '["67 cm", "50 cm", "40 cm", "25 cm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "f7d946344465", "answer_pdf_sha1": "922ed7560375", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02414', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列檢查中，何者的結果數值因老花眼的發生而降低？①融像性交叉圓柱鏡測試  ②調節靈敏度', '["動態視網膜檢影鏡單眼評估法（monocular estimation method，MEM）", "調節幅度", "僅", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "f7d946344465", "answer_pdf_sha1": "922ed7560375", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 42, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02415', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '根據年齡估測法，45歲的患者於工作距離40 cm，所需要的近用加入度為下列何者？', '["+1.00 D", "+1.50 D", "+2.00 D", "+2.50 D"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "f7d946344465", "answer_pdf_sha1": "922ed7560375", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 43, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02416', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '依據調節幅度一半原則（tentative add based on half the amplitude in reserve），給予受檢者+2.00 D的暫定 加入度（tentative ADD），而其工作距離為33 cm。此受檢者有多少調節幅度？', '["1.00 D", "2.00 D", "3.00 D", "5.00 D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "f7d946344465", "answer_pdf_sha1": "922ed7560375", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02417', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '藥品標籤上的文字往往都非常的小，在40 cm的距離測量下，若製造商告訴您上面的文字大小是logMAR 0.00， 在N標示法（N-notation）等價大小是多少？', '["N3", "N4", "N5", "N6"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "f7d946344465", "answer_pdf_sha1": "922ed7560375", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02418', 'optician', 'optician-moex-107-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受檢者提供以前的近距離視力檢查結果，紀錄為NVAcc. OD：0.4M OS：0.5M (slow) OU：0.4M，此紀錄 最大的缺點是下列何者？', '["沒有記錄到是遠用還是近用的視力", "沒有記錄到是矯正還是未矯正視力", "沒有記錄到當時測量的距離是多遠", "近距離檢測不可以使用M單位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:37+00:00", "source_pdf_sha1": "f7d946344465", "answer_pdf_sha1": "922ed7560375", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0807", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
